import { Request, Response, NextFunction } from 'express';
import jwt from 'jsonwebtoken';

interface DecodedUserPayload { // Define interface for your JWT payload
  id: string;
  email: string;
  // ...other user properties
}

// Extend Request type to include user property
declare module 'express' {
  export interface Request {
    user?: DecodedUserPayload;
  }
}

const protect = (req: Request, res: Response, next: NextFunction) => {
  let token: string | undefined;

  // 1. Check for JWT in Authorization header
  if (req.headers.authorization && req.headers.authorization.startsWith('Bearer')) {
    try {
      // 2. Extract token
      token = req.headers.authorization.split(' ')[1];

      // --- Debugging logs Start ---
      console.log('Incoming Authorization Header:', req.headers.authorization);
      console.log('Extracted Token:', token ? token.substring(0, 30) + '...' : 'None'); // Log partial token
      // --- Debugging logs End ---

      // 3. Verify token
      const JWT_SECRET = process.env.JWT_SECRET;
      if (!JWT_SECRET) {
        console.error('SERVER CONFIG ERROR: JWT_SECRET environment variable is not defined.');
        return res.status(500).json({ message: 'Server configuration error, please contact support.' });
      }

      const decoded = jwt.verify(token, JWT_SECRET) as DecodedUserPayload;
      // console.log('Successfully Decoded Token Payload:', decoded); // Debug decoded payload

      req.user = decoded; // Attach user payload to request

      next(); // Proceed to next middleware/route handler
    } catch (error) {
      console.error('Authentication Failed: Token verification failed.', error);
      // Distinguish between expired token and other failures for better client feedback
      if (error instanceof jwt.TokenExpiredError) {
        return res.status(401).json({ message: 'Not authorized, token expired. Please log in again.' });
      }
      return res.status(401).json({ message: 'Not authorized, invalid token.' });
    }
  }

  if (!token) {
    console.warn('Authentication Failed: No token provided in Authorization header.');
    return res.status(401).json({ message: 'Not authorized, no authentication token found.' });
  }
};

export { protect };

