    }
    return config;
  },
  error => {
    return Promise.reject(error);
  }
);

apient.interceptors.response.use(
  response => response,
  error => {
    if (error.response && error.response.status === 401) {
      console.warn('Authentication required or session expired. Redirecting to login...');
      // Clear any potentially invalid token
      localStorage.removeItem('authToken');
      // Redirect to login page
      window.location.href = '/login'; // Adjust this to your actual login route
    }
    return Promise.reject(error);
  }
);

